INSERT INTO `v1_9aa76be2d4c0787684a2199015f5f0e99293510b7f6d943c2d37354e8858bfa1` VALUES ("ＴＰダウンカット", 92428340, "boss_tp_down_cut", 2219, "バトル開始時、すべてのモンスターがＴＰダウン\n100％カット状態になる。");
INSERT INTO `v1_9aa76be2d4c0787684a2199015f5f0e99293510b7f6d943c2d37354e8858bfa1` VALUES ("ダメージ減衰", 92428340, 18, 2220, "すべてのモンスターが一度の行動で受けるダメージ値を減衰させる。ダメージ値が上昇するほど減衰率も上昇する。");
INSERT INTO `v1_9aa76be2d4c0787684a2199015f5f0e99293510b7f6d943c2d37354e8858bfa1` VALUES ("ＴＰ上昇上限付与", 92428340, 17, 2221, "バトル開始時、すべてのキャラのＴＰ上昇の上限値を150にする。");
INSERT INTO `v1_9aa76be2d4c0787684a2199015f5f0e99293510b7f6d943c2d37354e8858bfa1` VALUES ("ＨＰ吸収ダウン", 92428340, 9, 2222, "バトル開始時、すべてのキャラのＨＰ吸収を中ダウンさせる。");
INSERT INTO `v1_9aa76be2d4c0787684a2199015f5f0e99293510b7f6d943c2d37354e8858bfa1` VALUES ("ダメージカット", 92428340, "boss_damage_cut", 2223, "バトル開始時、すべてのモンスターがダメージ\n10％カット状態になる。");
